use aiken/collection/dict
use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

/// Exactly one token minted under the policy
fn exactly_one_token(
  tokens: dict.Dict<ByteArray, Int>,
) -> Bool {
  dict.size(tokens) == 1 && {
    let pairs = dict.to_pairs(tokens)
    when pairs is {
      [Pair(_, qty)] -> qty == 1
      _ -> False
    }
  }
}

validator nft_mint {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let one_token = exactly_one_token(tokens)
    let token_pairs = dict.to_pairs(tokens)
    let valid_name = when token_pairs is {
      [Pair(name, _)] -> bytearray.length(name) > 0
      _ -> False
    }
    let no_extra_mint = dict.size(assets.tokens(self.mint, policy_id)) <= 1
    one_token && valid_name && no_extra_mint
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_exactly_one_token_empty_is_false() {
  !exactly_one_token(dict.empty)
}

test prop_exactly_one_token_two_is_false(
  vals via fuzz.both(fuzz.bytearray_between(1, 10), fuzz.bytearray_between(1, 10)),
) {
  let (n1, n2) = vals
  if n1 == n2 {
    True
  } else {
    let d =
      dict.empty
        |> dict.insert(n1, 1)
        |> dict.insert(n2, 1)
    !exactly_one_token(d)
  }
}

test prop_exactly_one_token_single_correct(name via fuzz.bytearray_between(1, 32)) {
  let d = dict.empty |> dict.insert(name, 1)
  exactly_one_token(d)
}

test prop_exactly_one_token_single_wrong_qty(name via fuzz.bytearray_between(1, 32)) {
  let d = dict.empty |> dict.insert(name, 2)
  !exactly_one_token(d)
}

use aiken/collection/dict
use aiken/collection/list
use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{OutputReference, Transaction}

/// No single token name may have quantity > 1 (prevents fungible issuance)
fn no_fungible(tokens: dict.Dict<ByteArray, Int>) -> Bool {
  !dict.is_empty(tokens) && list.all(
    dict.to_pairs(tokens),
    fn(p) {
      let Pair(_, qty) = p
      qty == 1 || qty == -1
    },
  )
}

validator nft_no_fungible {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let all_nft = no_fungible(tokens)
    let token_count = dict.size(tokens)
    expect token_count > 0
    let names = dict.keys(tokens)
    let all_named = list.all(names, fn(name) { bytearray.length(name) > 0 })
    all_nft && all_named
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_no_fungible_empty_false() {
  !no_fungible(dict.empty)
}

test prop_no_fungible_qty_one(name via fuzz.bytearray_between(1, 32)) {
  let d = dict.empty |> dict.insert(name, 1)
  no_fungible(d)
}

test prop_no_fungible_qty_minus_one(name via fuzz.bytearray_between(1, 32)) {
  let d = dict.empty |> dict.insert(name, -1)
  no_fungible(d)
}

test prop_no_fungible_qty_two_fails(
  vals via fuzz.both(fuzz.bytearray_between(1, 16), fuzz.int_between(2, 50)),
) {
  let (name, qty) = vals
  let d = dict.empty |> dict.insert(name, qty)
  !no_fungible(d)
}

use aiken/collection/dict
use aiken/collection/list
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

const label_222: ByteArray = #"000de140"
const label_100: ByteArray = #"000643b0"

fn has_cip68_label(name: ByteArray, label: ByteArray) -> Bool {
  bytearray.length(name) >= 4 && bytearray.take(name, 4) == label
}

fn base_name(name: ByteArray) -> ByteArray {
  bytearray.drop(name, 4)
}

/// For every (222) token burned, the matching (100) reference must also be burned
fn burn_pairs_balanced(tokens: dict.Dict<ByteArray, Int>) -> Bool {
  list.all(
    dict.to_pairs(tokens),
    fn(p) {
      let Pair(name, qty) = p
      if has_cip68_label(name, label_222) {
        qty < 0 && {
          let ref_name = bytearray.concat(label_100, base_name(name))
          dict.get(tokens, ref_name) == Some(qty)
        }
      } else {
        True
      }
    },
  )
}

validator cip68_burn_pair {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    // Ensure there is at least one token being burned under this policy
    let token_list = dict.to_pairs(tokens)
    let has_burns =
      list.any(token_list, fn(p) { let Pair(_, qty) = p; qty < 0 })
    // Every (222) user token burned must have a matching (100) reference burned
    let pairs_ok = burn_pairs_balanced(tokens)
    // All burned tokens must carry a recognised CIP-68 label
    let all_labelled =
      list.all(
        token_list,
        fn(p) {
          let Pair(name, _) = p
          has_cip68_label(name, label_222) || has_cip68_label(name, label_100)
        },
      )
    has_burns && pairs_ok && all_labelled
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_burn_pair_empty() {
  burn_pairs_balanced(dict.empty)
}

test prop_base_name_roundtrip(suffix via fuzz.bytearray_between(1, 28)) {
  let full = bytearray.concat(label_222, suffix)
  base_name(full) == suffix
}

test prop_has_label_222(suffix via fuzz.bytearray_between(1, 28)) {
  let name = bytearray.concat(label_222, suffix)
  has_cip68_label(name, label_222)
}

test prop_has_label_too_short(name via fuzz.bytearray_between(0, 3)) {
  !has_cip68_label(name, label_222)
}

use aiken/collection/dict
use aiken/collection/list
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

const label_222: ByteArray = #"000de140"
const label_100: ByteArray = #"000643b0"

pub type CredentialMetadata {
  holder:  ByteArray,
  issuer:  ByteArray,
  expiry:  Int,
  role:    ByteArray,
}

fn has_label(name: ByteArray, label: ByteArray) -> Bool {
  bytearray.length(name) >= 4 && bytearray.take(name, 4) == label
}

fn strip_label(name: ByteArray) -> ByteArray {
  bytearray.drop(name, 4)
}

/// Every (222)X user token must have a paired (100)X reference token, both qty=1
fn credential_pairs_valid(tokens: dict.Dict<ByteArray, Int>) -> Bool {
  dict.to_pairs(tokens)
    |> list.all(
        fn(p) {
          let Pair(name, qty) = p
          if has_label(name, label_222) {
            qty == 1 && {
              let ref = bytearray.concat(label_100, strip_label(name))
              dict.get(tokens, ref) == Some(1)
            }
          } else {
            True
          }
        },
      )
}

validator cip68_credential_mint {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    // Must mint at least one token
    let non_empty = !dict.is_empty(tokens)
    // Every 222-labelled token must have a matching 100 reference token
    let pairs_ok = credential_pairs_valid(tokens)
    // Every token name must carry either the user label or the reference label
    let all_labelled =
      dict.to_pairs(tokens)
        |> list.all(
            fn(p) {
              let Pair(name, _) = p
              has_label(name, label_222) || has_label(name, label_100)
            },
          )
    // No token may be minted with a zero or negative quantity
    let positive_qtys =
      dict.to_pairs(tokens)
        |> list.all(fn(p) { let Pair(_, qty) = p; qty > 0 })
    non_empty && pairs_ok && all_labelled && positive_qtys
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_has_label_222_correct() {
  has_label(#"000de140ff", label_222)
}

test prop_has_label_100_correct() {
  has_label(#"000643b0ff", label_100)
}

test prop_has_label_short(name via fuzz.bytearray_between(0, 3)) {
  !has_label(name, label_222)
}

test prop_strip_label_roundtrip(suffix via fuzz.bytearray_between(1, 28)) {
  let full = bytearray.concat(label_222, suffix)
  strip_label(full) == suffix
}

test prop_pairs_valid_empty() {
  // empty tokens → valid (vacuously) but validator rejects via !is_empty check
  credential_pairs_valid(dict.empty)
}

test prop_pairs_valid_balanced() {
  let suffix = #"deadbeef"
  let tokens =
    dict.empty
      |> dict.insert(bytearray.concat(label_222, suffix), 1)
      |> dict.insert(bytearray.concat(label_100, suffix), 1)
  credential_pairs_valid(tokens)
}

test prop_pairs_invalid_missing_ref() {
  let suffix = #"deadbeef"
  let tokens = dict.empty |> dict.insert(bytearray.concat(label_222, suffix), 1)
  !credential_pairs_valid(tokens)
}

use aiken/collection/dict
use aiken/collection/list
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

const label_222: ByteArray = #"000de140"
const label_100: ByteArray = #"000643b0"

fn has_label(name: ByteArray, label: ByteArray) -> Bool {
  bytearray.length(name) >= 4 && bytearray.take(name, 4) == label
}

fn strip_label(name: ByteArray) -> ByteArray {
  bytearray.drop(name, 4)
}

fn is_cip68(name: ByteArray) -> Bool {
  has_label(name, label_222) || has_label(name, label_100)
}

/// All CIP-68 tokens must share the same suffix
fn uniform_suffix(tokens: dict.Dict<ByteArray, Int>) -> Bool {
  let suffixes =
    dict.to_pairs(tokens)
      |> list.filter_map(
          fn(p) {
            let Pair(name, _) = p
            if is_cip68(name) {
              Some(strip_label(name))
            } else {
              None
            }
          },
        )
  when suffixes is {
    [] -> True
    [first, ..rest] -> list.all(rest, fn(s) { s == first })
  }
}

fn credential_pairs_valid(tokens: dict.Dict<ByteArray, Int>) -> Bool {
  dict.to_pairs(tokens)
    |> list.all(
        fn(p) {
          let Pair(name, qty) = p
          if has_label(name, label_222) {
            qty == 1 && {
              let ref = bytearray.concat(label_100, strip_label(name))
              dict.get(tokens, ref) == Some(1)
            }
          } else {
            True
          }
        },
      )
}

validator cip68_uniform_suffix {
  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let non_empty = !dict.is_empty(tokens)
    let all_cip68 =
      dict.to_pairs(tokens)
        |> list.all(fn(p) { let Pair(name, _) = p; is_cip68(name) })
    let suffixes_uniform = uniform_suffix(tokens)
    let pairs_valid = credential_pairs_valid(tokens)
    let no_negative_qty =
      dict.to_pairs(tokens)
        |> list.all(fn(p) { let Pair(_, qty) = p; qty > 0 })
    non_empty && all_cip68 && suffixes_uniform && pairs_valid && no_negative_qty
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_uniform_suffix_empty() {
  uniform_suffix(dict.empty)
}

test prop_uniform_suffix_single(suffix via fuzz.bytearray_between(1, 28)) {
  let tokens =
    dict.empty
      |> dict.insert(bytearray.concat(label_222, suffix), 1)
      |> dict.insert(bytearray.concat(label_100, suffix), 1)
  uniform_suffix(tokens)
}

test prop_strip_label_consistent(suffix via fuzz.bytearray_between(1, 28)) {
  let n222 = bytearray.concat(label_222, suffix)
  let n100 = bytearray.concat(label_100, suffix)
  strip_label(n222) == strip_label(n100)
}

test prop_has_label_both(suffix via fuzz.bytearray_between(1, 28)) {
  let n222 = bytearray.concat(label_222, suffix)
  let n100 = bytearray.concat(label_100, suffix)
  has_label(n222, label_222) && has_label(n100, label_100)
}
